#include <bits/stdc++.h>
using namespace std;

const int N=450,M=4e4+650,INF=0x3f3f3f3f;

int n,F,D,s,t;
int head[N],ver[M],edge[M],nxt[M],tot=1;
int d[N],now[N];

void add(int u,int v){
    ver[++tot]=v,edge[tot]=1,nxt[tot]=head[u],head[u]=tot;
    ver[++tot]=u,edge[tot]=0,nxt[tot]=head[v],head[v]=tot;
}

bool bfs(){
    memset(d,0,sizeof(d));
    queue<int> q;
    q.push(s),d[s]=1,now[s]=head[s];
    while(q.size()){
        int x=q.front();
        q.pop();
        for(int i=head[x],y;i;i=nxt[i])
            if(!d[y=ver[i]] && edge[i]){
                d[y]=d[x]+1,now[y]=head[y];
                if(y==t)
                    return 1;
                q.push(y);
            }
    }
    return 0;
}

int Dinic(int x,int flow){
    if(x==t)
        return flow;
    int res=0;
    for(int i=now[x],y;i && res<flow;i=nxt[i]){
        now[x]=i,y=ver[i];
        if(d[y]==d[x]+1 && edge[i]){
            int tmp=Dinic(y,min(edge[i],flow-res));
            if(!tmp)
                d[y]=0;
            edge[i]-=tmp,edge[i^1]+=tmp;
            res+=tmp;
        }
    }
    return res;
}

int main(){
    scanf("%d%d%d",&n,&F,&D);
    s=2*n+F+D+1,t=2*n+F+D+2;
    for(int i=1;i<=F;i++)
        add(s,i);
    for(int i=1;i<=D;i++)
        add(F+i,t);
    for(int i=1;i<=n;i++)
        add(F+D+i,F+D+n+i);
    for(int i=1;i<=n;i++){
        int sf,sd,x;
        scanf("%d%d",&sf,&sd);
        while(sf--){
            scanf("%d",&x);
            add(x,F+D+i);
        }
        while(sd--){
            scanf("%d",&x);
            add(F+D+n+i,F+x);
        }
    }
    int flow,max_flow=0;
    while(bfs())
        while(flow=Dinic(s,INF))
            max_flow+=flow;
    printf("%d",max_flow);
    return 0;
}
